patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 59002cd934ab..45505f9334b0 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -2936,11 +2936,47 @@ static Value *simplifyICmpWithZero(CmpPredicate Pred, Value *LHS, Value *RHS,
   case ICmpInst::ICMP_ULE:
     if (isKnownNonZero(LHS, Q))
       return getFalse(ITy);
+    {
+      Value *X, *Y;
+      if (match(LHS, m_Or(m_Value(X), m_Value(Y)))) {
+        // (or X, Y) == 0  if X == 0 && Y == 0
+        // If X != Y, then at least one is non-zero -> false
+        if (isKnownNonEqual(X, Y, Q))
+          return getFalse(ITy);
+        if (Q.CxtI) {
+          if (std::optional<bool> NeImplied = isImpliedByDomCondition(
+                  ICmpInst::ICMP_NE, X, Y, Q.CxtI, Q.DL))
+            if (*NeImplied)
+              return getFalse(ITy);
+        }
+        // If either operand is known non-zero, the OR is non-zero -> false
+        if (isKnownNonZero(X, Q) || isKnownNonZero(Y, Q))
+          return getFalse(ITy);
+      }
+    }
     break;
   case ICmpInst::ICMP_NE:
   case ICmpInst::ICMP_UGT:
     if (isKnownNonZero(LHS, Q))
       return getTrue(ITy);
+    {
+      Value *X, *Y;
+      if (match(LHS, m_Or(m_Value(X), m_Value(Y)))) {
+        // (or X, Y) != 0  if X != 0 || Y != 0
+        // If X != Y, then at least one is non-zero -> true
+        if (isKnownNonEqual(X, Y, Q))
+          return getTrue(ITy);
+        if (Q.CxtI) {
+          if (std::optional<bool> NeImplied = isImpliedByDomCondition(
+                  ICmpInst::ICMP_NE, X, Y, Q.CxtI, Q.DL))
+            if (*NeImplied)
+              return getTrue(ITy);
+        }
+        // If either operand is known non-zero, the OR is non-zero -> true
+        if (isKnownNonZero(X, Q) || isKnownNonZero(Y, Q))
+          return getTrue(ITy);
+      }
+    }
     break;
   case ICmpInst::ICMP_SLT: {
     KnownBits LHSKnown = computeKnownBits(LHS, /* Depth */ 0, Q);
